            Uri.parse('fractalforge://view?type=mandelbrot&y=50000000000');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.y, closeTo(1e10, 1e6));
      });

      test('pan y below -1e10 is clamped to -1e10', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&y=-50000000000');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.y, closeTo(-1e10, 1e6));
