import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/services/presets/preset_storage_slot.dart';

class PresetStore {
  final SharedPreferences _prefs;

  PresetStore._(this._prefs);

  static Future<PresetStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return PresetStore._(prefs);
  }

  Future<List<FractalPreset>> loadUserPresets(String moduleId) async {
    return _loadSlot(PresetStorageSlot(moduleId));
  }

  Future<void> saveUserPreset(FractalPreset preset) async {
    final slot = PresetStorageSlot(preset.moduleId);
    final presets = _loadSlot(slot);
    // Check for duplicate ID and replace if exists
    final existingIndex = presets.indexWhere((p) => p.id == preset.id);
    final List<FractalPreset> updated;
    if (existingIndex >= 0) {
      // Replace existing preset with same ID
      updated = [...presets];
      updated[existingIndex] = preset;
    } else {
      // Add new preset
      updated = [...presets, preset];
    }
    await _saveSlot(slot, updated);
  }

  Future<void> deleteUserPreset(String moduleId, String presetId) async {
    final slot = PresetStorageSlot(moduleId);
    final presets = _loadSlot(slot);
    final updated = presets.where((preset) => preset.id != presetId).toList();
    await _saveSlot(slot, updated);
  }

  Future<void> updatePreset(
    String moduleId,
    String presetId, {
    required String name,
  }) async {
    final slot = PresetStorageSlot(moduleId);
    final presets = _loadSlot(slot);
    final index = presets.indexWhere((p) => p.id == presetId);
    if (index < 0) return;
    final updated = [...presets];
    updated[index] = presets[index].copyWith(name: name);
    await _saveSlot(slot, updated);
  }

  List<FractalPreset> _loadSlot(PresetStorageSlot slot) {
    return slot.decode(_prefs.getString(slot.key));
  }

  Future<void> _saveSlot(
    PresetStorageSlot slot,
    List<FractalPreset> presets,
  ) async {
    await _prefs.setString(slot.key, slot.encode(presets));
  }
}

import 'package:flutter_fractals/core/models/fractal_preset.dart';

/// SharedPreferences slot for one module's user presets.
///
/// A slot key is module-specific, so decoded entries must also prove they belong
/// to the same module. This keeps stale or corrupted payloads from leaking a
/// preset into another module's picker and from being preserved on the next save.
final class PresetStorageSlot {
  final String moduleId;

  const PresetStorageSlot(this.moduleId);

  String get key => 'user_presets_$moduleId';

  List<FractalPreset> decode(String? payload) {
    return _matchingModule(FractalPreset.listFromPrefs(payload))
        .toList(growable: false);
  }

  String encode(Iterable<FractalPreset> presets) {
    final input = presets.toList(growable: false);
    final matching = _matchingModule(input).toList(growable: false);

    assert(
      matching.length == input.length,
      'PresetStorageSlot can only encode presets for "$moduleId"',
    );

    return FractalPreset.listToPrefs(matching);
  }

  Iterable<FractalPreset> _matchingModule(Iterable<FractalPreset> presets) {
    return presets.where((preset) => preset.moduleId == moduleId);
  }
}

